async (params, browser) => {
  // Open user profile
  await browser.open(`https://x.com/${params.username}`)

  // Wait for page content
  await browser.waitForSelector('[data-testid=\'UserName\']', 15000)

  // Let page settle
  await browser.wait(1000)

  // Unfollow user with confirmation
  const result = await browser.evaluate(`const unfollowBtn = document.querySelector('[data-testid$="-unfollow"]'); if (!unfollowBtn) return { not_following: true, message: 'Not following this user' }; unfollowBtn.click(); await new Promise(r => setTimeout(r, 500)); const confirmBtn = document.querySelector('[data-testid="confirmationSheetConfirm"]'); if (confirmBtn) confirmBtn.click(); return { success: true, message: 'Unfollowed user' }`)

  return result
}
